import{_ as i,o as l,c as e,ae as t}from"./chunks/framework.D7zHIyZF.js";const r="/images/%E8%AF%BE%E7%A8%8B_%E8%AF%95%E5%8D%B7_%E9%A2%98%E7%9B%AE.png",o="/images/%E4%BF%9D%E5%AD%98%E8%AF%BE%E7%A8%8B%E5%B0%81%E9%9D%A2.png",s="/images/%E9%A2%98%E5%BA%93%E4%B8%8A%E4%BC%A0%E8%84%9A%E6%9C%AC.png",b=JSON.parse('{"title":"校园题库","description":"","frontmatter":{},"headers":[],"relativePath":"online/campus-question-bank.md","filePath":"online/campus-question-bank.md"}'),n={name:"online/campus-question-bank.md"};function h(c,a,d,p,u,_){return l(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="校园题库" tabindex="-1">校园题库 <a class="header-anchor" href="#校园题库" aria-label="Permalink to &quot;校园题库&quot;">​</a></h1><blockquote><p>欢迎大家一起构建属于自己学校的专属题库🎉</p></blockquote><h2 id="使用须知" tabindex="-1">使用须知 <a class="header-anchor" href="#使用须知" aria-label="Permalink to &quot;使用须知&quot;">​</a></h2><ol><li>校园题库中存在的题目将被题库配置优先调用，且不会被外校调用。</li><li>用户需要绑定学校，并完成<code>学生认证</code>。</li><li>题库有封禁机制，请不要上传与所在学校无关的题目。</li></ol><h2 id="题库结构" tabindex="-1">题库结构 <a class="header-anchor" href="#题库结构" aria-label="Permalink to &quot;题库结构&quot;">​</a></h2><p>课程 -&gt; 试卷 -&gt; 题目</p><div class="pic"><img src="'+r+'" alt="课程_试卷_题目.png"></div><h2 id="题库机制" tabindex="-1">题库机制 <a class="header-anchor" href="#题库机制" aria-label="Permalink to &quot;题库机制&quot;">​</a></h2><h3 id="_1-归档" tabindex="-1">1. 归档 <a class="header-anchor" href="#_1-归档" aria-label="Permalink to &quot;1. 归档&quot;">​</a></h3><ul><li>只有文件夹可以被归档</li><li>归档后，其他用户无法编辑，只能查看</li><li>文件夹创建者可以直接归档或取消归档，非创建者归档或取消归档需要发起投票</li></ul><h3 id="_2-垃圾站" tabindex="-1">2. 垃圾站 <a class="header-anchor" href="#_2-垃圾站" aria-label="Permalink to &quot;2. 垃圾站&quot;">​</a></h3><ul><li>题目删除后会先进入垃圾站，三天后永久删除，在此之前，皆可以恢复</li></ul><h3 id="_3-投票" tabindex="-1">3. 投票 <a class="header-anchor" href="#_3-投票" aria-label="Permalink to &quot;3. 投票&quot;">​</a></h3><ul><li>文件夹的归档，取消归档，删除操作需要发起投票</li><li>课程的删除需要发起投票</li><li>投票人数超过一半，投票通过</li></ul><h3 id="_4-封禁" tabindex="-1">4. 封禁 <a class="header-anchor" href="#_4-封禁" aria-label="Permalink to &quot;4. 封禁&quot;">​</a></h3><ul><li>封禁后的用户将无法使用校园题库，包括查看答案与编辑</li><li>其他使用不受限制</li></ul><h2 id="如何获取课程封面" tabindex="-1">如何获取课程封面 <a class="header-anchor" href="#如何获取课程封面" aria-label="Permalink to &quot;如何获取课程封面&quot;">​</a></h2><p>一般在学习通，或其他网课平台，右键封面图片，即可保存。</p><div class="pic"><img src="'+o+'" alt="保存课程封面.png"></div><h2 id="如何快速上传题目" tabindex="-1">如何快速上传题目 <a class="header-anchor" href="#如何快速上传题目" aria-label="Permalink to &quot;如何快速上传题目&quot;">​</a></h2><p>我写了一个油猴脚本来支持快速上传题目到校园题库<br><a href="https://scriptcat.org/zh-CN/script-show-page/5270" target="_blank" rel="noreferrer">https://scriptcat.org/zh-CN/script-show-page/5270</a></p><p>他会出现在页面的右下角，在选择课程与试卷后，点击解析，然后点击上传，脚本就会自动将页面中的题目上传至校园题库对应的文件夹。下次再次使用OCS网课助手时，就会优先调用校园题库中的题目，且不会消耗次数。</p><div class="pic"><img src="'+s+'" alt="题库上传脚本.png"></div> 脚本目前支持 <ol><li>学习通（作业，章节，随堂测试，考试）</li><li>中国大学Mooc（作业，检测）</li><li>智慧职教（作业，测验，考试）</li><li><s>智慧树</s>（待开发）</li><li><s>雨课堂</s>（待开发）</li></ol><p>更多平台正在开发中，如需新增支持，请联系开发者。</p><h2 id="举报" tabindex="-1">举报 <a class="header-anchor" href="#举报" aria-label="Permalink to &quot;举报&quot;">​</a></h2><ul><li>如果发现有违规题目，欢迎举报。</li><li>请将举报信息发送至邮箱 <a href="mailto:2669624618@qq.com" target="_blank" rel="noreferrer">2669624618@qq.com</a><br> 或加开发者QQ 2669624618</li><li>请在举报信息中包含被举报者的ID</li></ul>',28)])])}const q=i(n,[["render",h]]);export{b as __pageData,q as default};
